class AnalyticsNetworkInterceptor {
    static let shared = AnalyticsNetworkInterceptor()
    
    func interceptRequest(_ request: URLRequest) {
        let endpoint = request.url?.absoluteString ?? "unknown"
        let method = request.httpMethod ?? "unknown"
        let headers = request.allHTTPHeaderFields ?? [:]
        
        AnalyticsLogger.shared.logAPIRequest(
            endpoint: endpoint,
            method: method,
            headers: headers,
            body: request.httpBody
        )
    }
    
    func interceptResponse(_ response: HTTPURLResponse, data: Data?) {
        let endpoint = response.url?.absoluteString ?? "unknown"
        
        AnalyticsLogger.shared.logAPIResponse(
            endpoint: endpoint,
            statusCode: response.statusCode,
            headers: response.allHeaderFields,
            body: data
        )
    }
}

extension URLSession {
    func dataTaskWithLogging(with request: URLRequest, completionHandler: @escaping (Data?, URLResponse?, Error?) -> Void) -> URLSessionDataTask {
        AnalyticsNetworkInterceptor.shared.interceptRequest(request)
        
        return self.dataTask(with: request) { data, response, error in
            if let httpResponse = response as? HTTPURLResponse {
                AnalyticsNetworkInterceptor.shared.interceptResponse(httpResponse, data: data)
            }
            
            if let error = error {
                AnalyticsLogger.shared.logNetworkError(
                    url: request.url?.absoluteString ?? "unknown",
                    error: error,
                    requestBody: request.httpBody,
                    responseBody: data
                )
            }
            
            completionHandler(data, response, error)
        }
    }
}

class UserSessionManager {
    static let shared = UserSessionManager()
    private var currentUserId: String?
    private var sessionStartTime: Date?
    
    func startSession(userId: String, email: String, token: String) {
        currentUserId = userId
        sessionStartTime = Date()
        
        let deviceId = UIDevice.current.identifierForVendor?.uuidString ?? "unknown"
        AnalyticsLogger.shared.logSessionStart(userId: userId, deviceId: deviceId, token: token)
        AnalyticsLogger.shared.logAuthenticationSuccess(
            userId: userId,
            email: email,
            token: token,
            refreshToken: "refresh_\(token)"
        )
    }
    
    func endSession() {
        guard let userId = currentUserId, let startTime = sessionStartTime else { return }
        
        let duration = Date().timeIntervalSince(startTime)
        AnalyticsLogger.shared.logSessionEnd(userId: userId, duration: duration)
        
        currentUserId = nil
        sessionStartTime = nil
    }
    
    func getCurrentUserId() -> String? {
        return currentUserId
    }
}

